    ```java
import java.util.*;

public List<List<Integer>> arrangePairs(List<List<Integer>> pairs) {
    Map<Integer, List<Integer>> adj = new HashMap<>();
    for (List<Integer> pair : pairs) {
        adj.put(pair.get(0), pair);
    }

    List<List<Integer>> result = new ArrayList<>();
    int start = pairs.get(0).get(0);
    while (!adj.isEmpty()) {
        List<Integer> pair = adj.get(start);
        result.add(pair);
        start = pair.get(1);
        adj.remove(start);
    }

    return result;
}
```


